import { Metadata } from 'next';
import CourseDetailClient from './CourseDetailClient';

type Props = {
  params: { courseId: string };
};

// Helper function to optimize Cloudinary image URL for social sharing
function getOptimizedImageUrl(imageUrl: string, baseUrl: string): string {
  if (!imageUrl) return '';
  
  let absoluteUrl = '';
  
  // If already absolute URL, use as is
  if (imageUrl.startsWith('http://') || imageUrl.startsWith('https://')) {
    absoluteUrl = imageUrl;
  }
  // If relative URL, make it absolute
  else if (imageUrl.startsWith('/')) {
    absoluteUrl = `${baseUrl}${imageUrl}`;
  }
  // If Cloudinary URL without protocol, add https
  else if (imageUrl.includes('cloudinary.com')) {
    absoluteUrl = imageUrl.startsWith('//') ? `https:${imageUrl}` : `https://${imageUrl}`;
  }
  // Default: prepend origin
  else {
    absoluteUrl = `${baseUrl}${imageUrl.startsWith('/') ? '' : '/'}${imageUrl}`;
  }

  // Optimize Cloudinary URL for social sharing (1200x630 is optimal for Open Graph)
  if (absoluteUrl.includes('cloudinary.com') && !absoluteUrl.includes('/w_')) {
    // Check if URL already has transformations by looking for multiple '/upload/' occurrences
    const uploadIndex = absoluteUrl.indexOf('/upload/');
    const hasTransformations = uploadIndex !== -1 && absoluteUrl.indexOf('/upload/', uploadIndex + 1) !== -1;
    
    if (!hasTransformations) {
      // Add transformation parameters for optimal social sharing
      absoluteUrl = absoluteUrl.replace('/upload/', '/upload/w_1200,h_630,c_fill,f_auto,q_auto/');
    } else {
      // If transformations exist, ensure proper dimensions
      if (!absoluteUrl.includes('w_1200') && !absoluteUrl.includes('w_')) {
        absoluteUrl = absoluteUrl.replace('/upload/', '/upload/w_1200,h_630,c_fill,f_auto,q_auto/');
      }
    }
  }

  return absoluteUrl;
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const courseId = params.courseId;
  const baseUrl = process.env.NEXT_PUBLIC_APP_URL || process.env.VERCEL_URL 
    ? `https://${process.env.VERCEL_URL || process.env.NEXT_PUBLIC_APP_URL}` 
    : 'https://afroboosteur.vercel.app';

  try {
    // Fetch course data from API
    const response = await fetch(`${baseUrl}/api/courses/${courseId}/metadata`, {
      cache: 'no-store', // Ensure fresh data for metadata
    });

    if (!response.ok) {
      // Return default metadata if course not found
      return {
        title: 'Course - Afroboost Dance',
        description: 'Discover amazing dance courses',
      };
    }

    const { course } = await response.json();

    if (!course) {
      return {
        title: 'Course - Afroboost Dance',
        description: 'Discover amazing dance courses',
      };
    }

    const optimizedImageUrl = getOptimizedImageUrl(course.imageUrl, baseUrl);
    const courseUrl = `${baseUrl}/courses/${courseId}`;

    return {
      title: `${course.title} - Afroboost Dance`,
      description: course.description || 'Discover amazing dance courses',
      openGraph: {
        type: 'website',
        url: courseUrl,
        title: `${course.title} - Afroboost Dance`,
        description: course.description || 'Discover amazing dance courses',
        images: [
          {
            url: optimizedImageUrl,
            width: 1200,
            height: 630,
            alt: course.title,
          },
        ],
        siteName: 'Afroboost Dance',
      },
      twitter: {
        card: 'summary_large_image',
        title: `${course.title} - Afroboost Dance`,
        description: course.description || 'Discover amazing dance courses',
        images: [optimizedImageUrl],
      },
    };
  } catch (error) {
    console.error('Error generating metadata:', error);
    // Return default metadata on error
    return {
      title: 'Course - Afroboost Dance',
      description: 'Discover amazing dance courses',
    };
  }
}

export default function CourseDetail({ params }: Props) {
  return <CourseDetailClient />;
}
